from openai import OpenAI

client = OpenAI()   # reads OPENAI_API_KEY from environment

# Create an assistant — a reusable configuration
assistant = client.beta.assistants.create(
    name="order-support",
    instructions="""You are a customer support assistant for Acme Store.
You help customers check order status, file returns, and answer product questions.
Always confirm the customer's order ID before taking any action.""",
    model="gpt-4o",
    tools=[
        {"type": "code_interpreter"},   # built-in sandboxed Python
        {"type": "file_search"},         # built-in RAG
        # Custom function tools defined below
        {
            "type": "function",
            "function": {
                "name": "get_order_status",
                "description": "Get the current status of an order by its ID",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "order_id": {"type": "string", "description": "The order ID"},
                    },
                    "required": ["order_id"],
                },
            },
        },
        {
            "type": "function",
            "function": {
                "name": "initiate_return",
                "description": "Initiate a return for an order",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "order_id": {"type": "string"},
                        "reason": {"type": "string"},
                    },
                    "required": ["order_id", "reason"],
                },
            },
        },
    ],
)
print("Assistant ID:", assistant.id)

# Streaming with the EventHandler pattern
from openai import AssistantEventHandler
from typing_extensions import override
import json

class OrderHandler(AssistantEventHandler):
    @override
    def on_text_delta(self, delta, snapshot):
        print(delta.value, end="", flush=True)

    @override
    def on_tool_call_created(self, tool_call):
        print(f"\n[Tool call: {tool_call.type}]")

    @override
    def on_tool_call_delta(self, delta, snapshot):
        if delta.type == "code_interpreter" and delta.code_interpreter.input:
            print(delta.code_interpreter.input, end="", flush=True)

    @override
    def on_event(self, event):
        if event.event == "thread.run.requires_action":
            run_id   = event.data.id
            thread_id = event.data.thread_id
            tool_calls = event.data.required_action.submit_tool_outputs.tool_calls
            self.handle_requires_action(thread_id, run_id, tool_calls)

    def handle_requires_action(self, thread_id, run_id, tool_calls):
        outputs = []
        for tc in tool_calls:
            args = json.loads(tc.function.arguments)
            result = get_order_status(args["order_id"])
            outputs.append({"tool_call_id": tc.id, "output": json.dumps(result)})
        with client.beta.threads.runs.submit_tool_outputs_stream(
            thread_id=thread_id, run_id=run_id, tool_outputs=outputs,
            event_handler=OrderHandler(),
        ) as stream:
            stream.until_done()

# Use the streaming run
with client.beta.threads.runs.stream(
    thread_id=thread.id,
    assistant_id=assistant.id,
    event_handler=OrderHandler(),
) as stream:
    stream.until_done()
